    ; Point $12FF/$1300 at the success continuation.
    lda #.LOWORD(@landed)
    sta f:$7E12FF
    ; Poison $1200 so a buggy (wrapping) core lands somewhere else.
    sep #$20
    .a8
    lda #$00
    sta f:$7E1200
    rep #$30
    .a16
    .i16
    ; $12FF is reachable as bank-$00 low WRAM mirror.
    jmp ($12FF)
@landed:
    nop
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
.endproc

