    .a16
    .i16
    phk
    plb               ; DBR = $00
    ldx #$8006
    sep #$20
    .a8
    lda $FFFF,X
    cmp #$A1
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; abs,X did not carry into bank $01
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
.endproc

