    .a16
    .i16
    ; Identical instruction, identical operand — only D changes. D=$0000 costs N cycles,
    ; D=$0001 costs N+1, because the penalty keys off DL != 0.
    rep #$30
    .a16
    .i16
    ldx #$0000
    lda #$0000
    tcd               ; DL = $00: no penalty
    jsr hv_begin
    lda $10,x
    lda $10,x
    lda $10,x
    lda $10,x
    lda $10,x
    lda $10,x
    lda $10,x
    lda $10,x
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sta f:$7E0080     ; baseline
    lda #$0001
    tcd               ; DL = $01: one extra cycle per access
    jsr hv_begin
    lda $10,x
    lda $10,x
    lda $10,x
    lda $10,x
    lda $10,x
    lda $10,x
    lda $10,x
    lda $10,x
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sec
    sbc f:$7E0080
    cmp #$000A
    bcs :+
    jmp @fail1
  :
    cmp #$000F
    bcc :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; direct-page +1 w penalty (DL != 0) not applied
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
.endproc

; A5.02 — +1 p on indexed reads
; provenance: Documented (WDC datasheet; superfamicom.org cycle-count tables)
.proc test_a5_02
    .a16
    .i16
    ; lda $10FF,X with X=$01 crosses a page; with X=$00 it does not.
    ; The index must be 8-BIT: with a 16-bit index the cycle is unconditional, so the two
    ; measurements would be identical and the test would prove nothing.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$10
    .i8
    ldx #$00
    jsr hv_begin
    lda a:$10FF,x
    lda a:$10FF,x
    lda a:$10FF,x
    lda a:$10FF,x
    lda a:$10FF,x
    lda a:$10FF,x
    lda a:$10FF,x
    lda a:$10FF,x
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sta f:$7E0080
    sep #$10
    .i8
    ldx #$01          ; now every access crosses into the next page
    jsr hv_begin
    lda a:$10FF,x
    lda a:$10FF,x
    lda a:$10FF,x
    lda a:$10FF,x
    lda a:$10FF,x
    lda a:$10FF,x
    lda a:$10FF,x
    lda a:$10FF,x
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sec
    sbc f:$7E0080
    cmp #$000A
    bcs :+
    jmp @fail1
  :
    cmp #$000F
    bcc :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; indexed read did not pay the +1 p page-cross penalty
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
.endproc

; A5.03 — Stores always pay +1 p
; provenance: Documented (WDC datasheet; superfamicom.org cycle-count tables)
.proc test_a5_03
    .a16
    .i16
    ; sta $10FF,X costs the same whether or not it crosses a page — stores always pay the
    ; cycle, so unlike the load in A5.02 there is no difference to find. Same 8-bit index.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$10
    .i8
    ldx #$00
    jsr hv_begin
    sta a:$10FF,x
    sta a:$10FF,x
    sta a:$10FF,x
    sta a:$10FF,x
    sta a:$10FF,x
    sta a:$10FF,x
    sta a:$10FF,x
    sta a:$10FF,x
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sta f:$7E0080
    sep #$10
    .i8
    ldx #$01          ; crosses a page, but must cost the same
    jsr hv_begin
    sta a:$10FF,x
    sta a:$10FF,x
    sta a:$10FF,x
    sta a:$10FF,x
    sta a:$10FF,x
    sta a:$10FF,x
    sta a:$10FF,x
    sta a:$10FF,x
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sec
    sbc f:$7E0080
    cmp #$8000
    bcc :+
    eor #$FFFF
    inc a             ; negate: take the magnitude
  :
    cmp #$0003
    bcc :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; indexed store timing changed with page crossing (it must not)
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
.endproc

; A5.04 — Decimal costs no cycles
