    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sta f:$7E0080     ; baseline
    sep #$20
    .a8
    sed
    jsr hv_begin
    clc
    adc #$01
    clc
    adc #$01
    clc
    adc #$01
    clc
    adc #$01
    clc
    adc #$01
    clc
    adc #$01
    clc
    adc #$01
    clc
    adc #$01
    jsr hv_end
    sep #$20
    .a8
    cld               ; leave decimal before any further arithmetic
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sec
    sbc f:$7E0080
    cmp #$8000
    bcc :+
    eor #$FFFF
    inc a             ; negate: take the magnitude
  :
    cmp #$0003
    bcc :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
