    lda #$02
    sta f:$7EE010
    jmp test_restore
.endproc

; A5.05 — 16-bit RMW is +2
; provenance: Documented (WDC datasheet (corrects undisbeliever's table))
.proc test_a5_05
    .a16
    .i16
    ; ASL dp with m=1 vs m=0. The 16-bit form reads and writes an extra byte.
    rep #$30
    .a16
    .i16
    lda #$0000
    tcd
    sep #$20          ; 8-bit accumulator -> 8-bit RMW
    .a8
    jsr hv_begin
    asl $20
    asl $20
    asl $20
    asl $20
    asl $20
    asl $20
    asl $20
    asl $20
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sta f:$7E0080
    rep #$20          ; 16-bit accumulator -> 16-bit RMW
    .a16
    jsr hv_begin
    asl $20
    asl $20
    asl $20
    asl $20
    asl $20
    asl $20
    asl $20
    asl $20
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sec
    sbc f:$7E0080
    cmp #$001E
    bcs :+
    jmp @fail1
  :
    cmp #$0023
    bcc :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; 16-bit RMW is not +2 cycles over the 8-bit form
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
.endproc

; A5.06 — Taken branch costs +1
; provenance: Documented (WDC datasheet)
.proc test_a5_06
    .a16
    .i16
    ; BCC taken vs not taken, same instruction, same target, one cycle apart.
    rep #$30
    .a16
    .i16
    sec               ; carry set -> BCC never taken
    jsr hv_begin
    bcc *+2
    bcc *+2
    bcc *+2
    bcc *+2
    bcc *+2
    bcc *+2
    bcc *+2
    bcc *+2
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sta f:$7E0080
    clc               ; carry clear -> BCC always taken
    jsr hv_begin
    bcc *+2
    bcc *+2
    bcc *+2
    bcc *+2
    bcc *+2
    bcc *+2
    bcc *+2
    bcc *+2
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sec
    sbc f:$7E0080
    cmp #$000A
    bcs :+
    jmp @fail1
  :
    cmp #$000F
    bcc :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; a taken branch did not cost one extra cycle
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
.endproc

; A6.01 — BRK vectors natively
; provenance: Documented (WDC datasheet; SNESdev Wiki vectors)
.proc test_a6_01
    .a16
    .i16
    jmp @start
@handler:
    sep #$20
    .a8
    lda #$A5
    sta f:$7E0090     ; prove the handler actually ran
    rep #$30
    .a16
    .i16
    rti
@start:
    rep #$30
    .a16
    .i16
    sep #$20
    .a8
    lda #$00
    sta f:$7E0090
    rep #$30
    .a16
    .i16
    lda #.LOWORD(@handler)
    sta a:V_BRK_VEC
    brk
    .byte $EA         ; BRK signature byte
    sep #$20
    .a8
    lda f:$7E0090
    cmp #$A5
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; native BRK did not reach the installed handler
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
.endproc

