; A6.06 — Emulation pushes 3 bytes
; provenance: Documented (WDC datasheet)
.proc test_a6_06
    .a16
    .i16
    jmp @start
@handler:
    tsx               ; X = S low byte (8-bit index in emulation)
    txa
    sta f:$7E0098
    rti
@start:
    rep #$30
    .a16
    .i16
    lda #.LOWORD(@handler)
    sta a:V_BRK_VEC
    ; Poison both slots so a handler that never runs cannot look like a pass.
    sep #$20
    .a8
    lda #$EE
    sta f:$7E0098
    lda #$EE
    sta f:$7E0099
    sec
    xce               ; -> emulation
    .a8
    .i8
    tsx
    txa
    sta f:$7E0099     ; S low byte before the interrupt
    brk
    .byte $EA
    clc
    xce               ; -> native (m/x stay 1: still 8-bit)
    .a8
    .i8
    sep #$20
    .a8
    lda f:$7E0099
    sec
    sbc f:$7E0098
    cmp #$03
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; emulation interrupt did not push exactly 3 bytes
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
.endproc

; A6.07 — BRK skips signature byte
; provenance: Documented (WDC datasheet)
.proc test_a6_07
    .a16
    .i16
    jmp @start
@handler:
    rti
@start:
    rep #$30
    .a16
    .i16
    lda #.LOWORD(@handler)
    sta a:V_BRK_VEC
    clc               ; RTI restores P, so carry comes back CLEAR...
    brk
    .byte $38         ; ...unless PC returned here, where $38 is SEC
    php
    sep #$20
    .a8
    pla
    and #$01          ; carry
    cmp #$00
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; BRK pushed PC+1, so the signature byte executed
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
.endproc

; A6.08 — WDM is a 2-byte NOP
; provenance: Documented (WDC datasheet)
.proc test_a6_08
    .a16
    .i16
    ; WDM consumes its operand byte. If it did not, the $38 below would run as SEC.
    rep #$30
    .a16
    .i16
    lda #$1234
    clc
    .byte $42, $38    ; WDM #$38  (the operand is SEC if wrongly executed)
    sta f:$7E00A0     ; stash A before the carry check clobbers it
    php
    sep #$20
    .a8
    pla
    and #$01          ; carry
    cmp #$00
    beq :+
    jmp @fail1
  :
    rep #$30
    .a16
    .i16
    lda f:$7E00A0
    cmp #$1234
    beq :+
    jmp @fail2
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; WDM did not consume its operand byte
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
@fail2:
    ; WDM disturbed the accumulator
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jmp test_restore
.endproc

